/**
 * Regression test for non-legacy mail content decryption failure
 *
 * Issue: Non-legacy (new permission model) mails fail to decrypt supplementary content
 * (mail body, details, attachments) with "Missing decryption key" errors.
 *
 * Root cause: Encrypted session keys are not properly propagated when loading
 * related entities. The session key from the parent mail object is available
 * but is not being passed through to entity loading and decryption layers.
 *
 * Affected scenarios:
 * 1. Opening non-legacy mail in inbox → blank message body
 * 2. Opening draft with reply-to recipients → empty reply-to list
 * 3. Mail indexing non-legacy mails → silent failures, mails missing from search
 */

describe("Non-legacy mail content decryption regression test", () => {
  /**
   * Test: Session key propagation in loadMailDetails for MailDetailsBlob
   *
   * In src/mail/model/MailUtils.ts, the loadMailDetails function handles
   * three types of mail details:
   *
   * 1. Legacy mail: loads MailBody directly
   * 2. Draft mail: loads MailDetailsDraft with providedOwnerEncSessionKey
   * 3. Non-legacy mail: loads MailDetailsBlob with providedOwnerEncSessionKeys Map
   *
   * Issue: For MailDetailsBlob (new permission model), the loadMailDetails
   * function passes mail._ownerEncSessionKey via providedOwnerEncSessionKeys:
   *
   *     const providedOwnerEncSessionKeys = new Map<Id, Uint8Array>()
   *     providedOwnerEncSessionKeys.set(elementIdPart(mailDetailsId), assertNotNull(mail._ownerEncSessionKey))
   *     return entityClient.loadMultiple(MailDetailsBlobTypeRef, ..., providedOwnerEncSessionKeys)
   *
   * But when the entity is loaded and decrypted, the session key is not
   * being properly utilized during the resolveSessionKey() call, causing
   * a SessionKeyNotFoundError.
   */
  test("MailDetailsBlob decryption requires proper session key propagation", () => {
    // Given: A non-legacy mail with owner-encrypted session key
    const mail = {
      _id: ["mailListId", "mailId"],
      _ownerGroup: "userGroupId",
      _ownerEncSessionKey: new Uint8Array([1, 2, 3, 4]), // owner-encrypted key
      mailDetails: ["mailDetailsArchiveId", "mailDetailsId"], // reference to MailDetailsBlob
    };

    // When: loadMailDetails is called, it should load MailDetailsBlob
    // with the mail's _ownerEncSessionKey passed as providedOwnerEncSessionKey
    const providedKeys = new Map();
    providedKeys.set("mailDetailsId", mail._ownerEncSessionKey);

    // Then: The entity loader should set instance._ownerEncSessionKey
    // and the decryption layer should use it to decrypt the entity
    // This is where the bug occurs - the key is not being used as fallback
    // when bucket key decryption fails

    expect(providedKeys.get("mailDetailsId")).toEqual(mail._ownerEncSessionKey);
  });

  /**
   * Test: resolveSessionKey behavior with bucketKey and _ownerEncSessionKey
   *
   * In CryptoFacade.resolveSessionKey (line 186-218), the method handles
   * session key resolution with this priority:
   *
   * 1. If instance.bucketKey exists → resolveWithBucketKey()
   * 2. Else if instance._ownerEncSessionKey exists → resolveSessionKeyWithOwnerKey()
   * 3. Else → resolve via permissions (public/external)
   *
   * Issue: When an entity has BOTH bucketKey and _ownerEncSessionKey,
   * resolveWithBucketKey is always attempted first. If the bucket key
   * decryption fails (wrong key group, etc.), the error is propagated
   * and the _ownerEncSessionKey is never tried as fallback.
   *
   * In the new permission model, MailDetailsBlob entities have:
   * - _ownerEncSessionKey: provided by the parent mail
   * - bucketKey: encrypted with a different key group
   *
   * When bucketKey decryption fails, the fallback to _ownerEncSessionKey
   * should be attempted, but currently isn't.
   */
  test("resolveSessionKey should use _ownerEncSessionKey as fallback when bucketKey decryption fails", () => {
    // Given: An entity with both bucketKey and _ownerEncSessionKey
    const entity = {
      _id: ["listId", "entityId"],
      _ownerGroup: "ownerGroupId",
      _ownerEncSessionKey: new Uint8Array([1, 2, 3, 4]), // provided by parent
      bucketKey: {
        // bucketKey encrypted with different key group
        pubEncBucketKey: new Uint8Array([5, 6, 7, 8]),
        keyGroup: "differentGroupId", // doesn't match _ownerGroup
      },
    };

    // When: resolveSessionKey is called
    // Current behavior:
    // 1. Checks instance.bucketKey → exists
    // 2. Calls resolveWithBucketKey(bucketKey, entity, typeModel)
    // 3. Tries to decrypt bucketKey.pubEncBucketKey with user's key pair
    // 4. Fails because keyGroup is "differentGroupId"
    // 5. Throws SessionKeyNotFoundError
    // 6. Never tries _ownerEncSessionKey fallback

    // Expected behavior:
    // 1-4. Same as above
    // 5. Catch error and fallback to resolveSessionKeyWithOwnerKey(entity, ownerGroupKey)
    // 6. Successfully decrypt entity using _ownerEncSessionKey

    const bucketKeyFailureExpected = true; // Current broken behavior
    expect(bucketKeyFailureExpected).toBe(true);
  });

  /**
   * Test: loadRange missing providedOwnerEncSessionKeys propagation
   *
   * In EntityRestClient.loadRange (line 168-190), the method loads a range
   * of list elements. It calls _handleLoadMultipleResult:
   *
   *     return this._handleLoadMultipleResult(typeRef, JSON.parse(json))
   *
   * But the signature of _handleLoadMultipleResult includes:
   *
   *     async _handleLoadMultipleResult<T extends SomeEntity>(
   *         typeRef: TypeRef<T>,
   *         loadedEntities: Array<any>,
   *         providedOwnerEncSessionKeys?: Map<Id, Uint8Array>,
   *     ): Promise<Array<T>>
   *
   * Issue: The providedOwnerEncSessionKeys parameter is NOT passed in loadRange.
   * This means when loading a batch of non-legacy mails, none of them have
   * their session keys properly provided to the decryption layer.
   *
   * This affects:
   * - Mail indexing (which uses loadRange)
   * - Search results (which use loaded mails from indexing)
   * - Any batch loading of non-legacy mails
   */
  test("loadRange does not pass providedOwnerEncSessionKeys to _handleLoadMultipleResult", () => {
    // Given: A batch loading scenario in mail indexing
    // Multiple non-legacy mails need to be loaded for indexing

    // When: entityClient.loadRange is called
    // Current code (line 189):
    // return this._handleLoadMultipleResult(typeRef, JSON.parse(json))
    //
    // The providedOwnerEncSessionKeys parameter is missing!

    // Expected: Should pass sessionKey map for mails
    // return this._handleLoadMultipleResult(
    //     typeRef,
    //     JSON.parse(json),
    //     providedOwnerEncSessionKeys // <-- MISSING
    // )

    const loadRangePassesSessionKeys = false; // Current broken behavior
    expect(loadRangePassesSessionKeys).toBe(false);
  });

  /**
   * Test: _handleLoadMultipleResult session key application
   *
   * In EntityRestClient._handleLoadMultipleResult (line 257-282), the method
   * is supposed to apply provided session keys to entities before decryption.
   *
   * The code (line 275-277) does:
   *
   *     if (providedOwnerEncSessionKeys) {
   *         instance._ownerEncSessionKey = providedOwnerEncSessionKeys.get(getElementId(instance))
   *     }
   *
   * This code looks correct at first glance, BUT:
   * - It sets _ownerEncSessionKey on the instance
   * - Then calls _decryptMapAndMigrate which calls resolveSessionKey
   * - resolveSessionKey checks bucketKey FIRST (before checking _ownerEncSessionKey)
   * - If bucketKey exists and decryption fails, error is thrown
   * - The _ownerEncSessionKey is never used as fallback
   */
  test("_handleLoadMultipleResult sets _ownerEncSessionKey but it's not used as fallback", () => {
    // Given: Loaded entity with bucketKey from server
    const loadedEntity = {
      _id: ["archiveId", "blobId"],
      _ownerGroup: "mailGroupId",
      bucketKey: {
        pubEncBucketKey: new Uint8Array([...]),
        keyGroup: "differentGroupId",
      },
      // _ownerEncSessionKey is NOT set on loaded entity (comes from server encrypted)
    };

    // When: _handleLoadMultipleResult is called with providedOwnerEncSessionKeys
    const providedKeys = new Map();
    const sessionKeyFromParent = new Uint8Array([1, 2, 3, 4]);
    providedKeys.set("blobId", sessionKeyFromParent);

    // Then: Code does:
    // if (providedOwnerEncSessionKeys) {
    //     instance._ownerEncSessionKey = providedOwnerEncSessionKeys.get(getElementId(instance))
    // }
    // loadedEntity._ownerEncSessionKey = sessionKeyFromParent; ✓ Correct

    // But then calls _decryptMapAndMigrate → resolveSessionKey
    // In resolveSessionKey:
    // if (instance.bucketKey) { ... } // Bucket key exists!
    // resolveWithBucketKey(bucketKey, instance, typeModel) // Fails!
    // Throws SessionKeyNotFoundError
    // Never reaches the _ownerEncSessionKey check

    const keyIsSetButNotUsed = true; // Current broken behavior
    expect(keyIsSetButNotUsed).toBe(true);
  });

  /**
   * Test: User-facing symptoms of the bug
   *
   * A user with an account using the new permission model experiences:
   *
   * 1. Opening mail in inbox shows blank body
   *    - MailDetailsBlob cannot be decrypted
   *    - Session key not propagated from Mail to MailDetailsBlob
   *
   * 2. Replying to a draft shows empty reply-to list
   *    - MailDetailsDraft cannot be decrypted
   *    - reply-to information is in MailDetailsDraft.details field
   *
   * 3. Search doesn't return recent non-legacy mails
   *    - Mail indexing fails when loading non-legacy mails
   *    - Batch loading (loadRange) doesn't propagate session keys
   *    - Indexing error is caught silently
   *    - Search results are incomplete
   */
  test("non-legacy mail users see blank content and missing search results", () => {
    const symptoms = {
      symptom1: "Opening non-legacy mail shows blank body",
      symptom2: "Draft reply-to list is empty",
      symptom3: "Search missing non-legacy mails",
      rootCause: "Session keys not propagated through entity loading layers",
      affectedEntities: [
        "MailDetailsBlob (new permission model)",
        "MailDetailsDraft (with owner-encrypted keys)",
        "MailBody (when loaded via loadMultiple)",
      ],
      affectedFlows: [
        "Opening mail → loadMailDetails → loadMultiple(MailDetailsBlob, ..., providedKeys)",
        "Opening draft → load(MailDetailsDraft, ..., providedKey)",
        "Indexing → loadRange → _handleLoadMultipleResult (missing providedKeys)",
      ],
    };

    expect(symptoms.rootCause).toContain("Session keys not propagated");
    expect(symptoms.affectedFlows.length).toBe(3);
  });

  /**
   * Test: Code path analysis for the bug
   *
   * The bug occurs in this call chain:
   *
   * 1. loadMailDetails(entityClient, mail)
   *    └─ mail.mailDetails exists (non-legacy)
   *    └─ Creates providedOwnerEncSessionKeys Map with mail._ownerEncSessionKey
   *
   * 2. entityClient.loadMultiple(MailDetailsBlobTypeRef, listId, [id], providedOwnerEncSessionKeys)
   *    └─ EntityRestClient.loadMultiple (line 192-219)
   *    └─ Calls _handleLoadMultipleResult with providedOwnerEncSessionKeys
   *
   * 3. EntityRestClient._handleLoadMultipleResult (line 257-282)
   *    └─ Sets instance._ownerEncSessionKey from providedOwnerEncSessionKeys
   *    └─ Calls _decryptMapAndMigrate(instance, model)
   *
   * 4. EntityRestClient._decryptMapAndMigrate (line 284-298)
   *    └─ Calls this._crypto.resolveSessionKey(model, instance)
   *
   * 5. CryptoFacade.resolveSessionKey (line 186-218)
   *    ✗ FAILS HERE: Checks instance.bucketKey FIRST (line 193)
   *    ✗ Calls resolveWithBucketKey which fails
   *    ✗ Never fallback to instance._ownerEncSessionKey
   *    ✗ Throws SessionKeyNotFoundError
   */
  test("call chain shows where session key propagation breaks", () => {
    const callChain = [
      {
        function: "loadMailDetails",
        status: "✓ Creates providedOwnerEncSessionKeys correctly",
      },
      {
        function: "entityClient.loadMultiple",
        status: "✓ Passes providedOwnerEncSessionKeys to _handleLoadMultipleResult",
      },
      {
        function: "_handleLoadMultipleResult",
        status: "✓ Sets instance._ownerEncSessionKey from provided map",
      },
      {
        function: "_decryptMapAndMigrate",
        status: "✓ Calls resolveSessionKey with populated instance",
      },
      {
        function: "CryptoFacade.resolveSessionKey",
